import React, { useState } from "react";

export default function DepositScreen({ onDeposit, setCurrentScreen, showToast }) {
  const [amount, setAmount] = useState("");

  const handleDeposit = () => {
    const value = parseFloat(amount);
    if (!amount || isNaN(value) || value <= 0) {
      showToast("Enter a valid amount", "error");
      return;
    }
    onDeposit(value);
    setAmount("");
    showToast(`Successfully deposited $${value}`, "success");
    setCurrentScreen("Dashboard"); // go back to dashboard
  };

  return (
    <div className="px-6 pb-24 bg-gray-50 min-h-screen">
      <h1 className="text-2xl font-bold mb-6">Deposit Funds</h1>

      <div className="bg-white p-6 rounded-xl border border-gray-100 shadow-sm space-y-4">
        <input
          type="number"
          placeholder="Enter amount"
          className="w-full border border-gray-200 rounded-xl px-4 py-3 focus:outline-none focus:ring-2 focus:ring-teal-500"
          value={amount}
          onChange={(e) => setAmount(e.target.value)}
        />
        <button
          onClick={handleDeposit}
          className="w-full py-3 bg-teal-600 text-white rounded-xl hover:bg-teal-700 transition-colors"
        >
          Deposit
        </button>
      </div>
    </div>
  );
}
